read_candidate_file <- function(path) {
  out <- tryCatch({
    if (str_detect(str_to_lower(path), "\\.csv$")) {
      readr::read_csv(path, show_col_types = FALSE, progress = FALSE)
    } else if (str_detect(str_to_lower(path), "\\.tsv$")) {
      readr::read_tsv(path, show_col_types = FALSE, progress = FALSE)
    } else if (str_detect(str_to_lower(path), "\\.xlsx?$") && has_readxl) {
      readxl::read_excel(path)
    } else {
      NULL
    }
  }, error = function(e) NULL)
  out
}

summarise_candidate_features <- function(dat, source_path) {
  if (is.null(dat) || !"AnimalNum" %in% names(dat)) return(NULL)

  dat <- dat %>% mutate(AnimalNum = as.character(AnimalNum))

  # Prefer first active-phase / first cage-change rows if those columns exist.
  if ("Phase" %in% names(dat)) {
    active_rows <- str_detect(str_to_lower(as.character(dat$Phase)), "active|dark|night")
    if (any(active_rows, na.rm = TRUE)) dat <- dat[active_rows, , drop = FALSE]
  }
  if ("CageChange" %in% names(dat)) {
    cc <- as.character(dat$CageChange)
    cc_num <- suppressWarnings(as.numeric(str_extract(cc, "\\d+")))
    if (any(is.finite(cc_num))) {
      first_cc <- unique(cc[which(cc_num == min(cc_num, na.rm = TRUE))])[1]
      dat <- dat %>% filter(as.character(CageChange) == first_cc)
    }
  }

  numeric_cols <- names(dat)[vapply(dat, is.numeric, logical(1))]
  numeric_cols <- setdiff(numeric_cols, c("TimeIndex", "Bin", "bin", "early_rank"))
  numeric_cols <- numeric_cols[!is_leakage_name(numeric_cols)]
  if (length(numeric_cols) == 0) return(NULL)

  source_stub <- tools::file_path_sans_ext(basename(source_path)) %>% clean_name()

  out <- dat %>%
    group_by(AnimalNum) %>%
    summarise(across(all_of(numeric_cols), ~mean(.x, na.rm = TRUE)), .groups = "drop")

  # Drop columns that are entirely NA/Inf after aggregation.
  keep <- names(out)[names(out) == "AnimalNum" | vapply(out, function(x) any(is.finite(suppressWarnings(as.numeric(x)))), logical(1))]
  out <- out[, keep, drop = FALSE]
  if (ncol(out) <= 1) return(NULL)

  names(out)[names(out) != "AnimalNum"] <- paste0(source_stub, "__", names(out)[names(out) != "AnimalNum"])
  out
}

