# ------------------------------------------------
# MODEL FITTING
# ------------------------------------------------

prepare_model_frame <- function(dat, predictors) {
  cols <- unique(c("AnimalNum", "Group", "Sex", outcome_col, predictors))
  cols <- cols[cols %in% names(dat)]
  mf <- dat %>% select(all_of(cols))

  numeric_cols <- names(mf)[vapply(mf, is.numeric, logical(1))]
  numeric_cols <- setdiff(numeric_cols, outcome_col)
  mf <- impute_numeric_median(mf, numeric_cols)

  # Scale numeric predictors for comparability and glmnet stability.
  mf <- mf %>% mutate(across(all_of(numeric_cols), safe_scale))

  if ("Sex" %in% names(mf)) mf$Sex <- factor(mf$Sex)
  if ("Group" %in% names(mf)) mf$Group <- factor(mf$Group)
  mf
}

fit_predict_lm_loo <- function(dat, predictors, model_name) {
  mf <- prepare_model_frame(dat, predictors)
  preds <- rep(NA_real_, nrow(mf))
  coefs <- list()

  for (i in seq_len(nrow(mf))) {
    train <- mf[-i, , drop = FALSE]
    test <- mf[i, , drop = FALSE]
    form <- make_formula(outcome_col, predictors[predictors %in% names(mf)])
    fit <- try(lm(form, data = train), silent = TRUE)
    if (inherits(fit, "try-error")) next
    preds[i] <- tryCatch(as.numeric(predict(fit, newdata = test)), error = function(e) NA_real_)
    sm <- try(summary(fit)$coefficients, silent = TRUE)
    if (!inherits(sm, "try-error")) {
      coefs[[i]] <- tibble(
        Model = model_name,
        held_out_animal = mf$AnimalNum[i],
        term = rownames(sm),
        estimate = sm[, 1],
        std_error = sm[, 2],
        statistic = sm[, 3],
        p_value = sm[, 4]
      )
    }
  }

  list(
    predictions = mf %>%
      transmute(
        AnimalNum,
        Group = if ("Group" %in% names(.)) as.character(Group) else NA_character_,
        Sex = if ("Sex" %in% names(.)) as.character(Sex) else NA_character_,
        observed = .data[[outcome_col]],
        predicted = preds,
        residual = observed - predicted,
        abs_residual = abs(residual),
        Model = model_name,
        Method = "LOAO linear model"
      ),
    coefficients = bind_rows(coefs)
  )
}

fit_predict_glmnet_loo <- function(dat, predictors, model_name, alpha = 0.5) {
  if (!has_glmnet || length(predictors) == 0) return(fit_predict_lm_loo(dat, predictors, model_name))

  mf <- prepare_model_frame(dat, predictors)
  predictors <- predictors[predictors %in% names(mf)]
  preds <- rep(NA_real_, nrow(mf))
  coef_rows <- list()

  for (i in seq_len(nrow(mf))) {
    train <- mf[-i, , drop = FALSE]
    test <- mf[i, , drop = FALSE]
    x_train <- try(model.matrix(make_formula(outcome_col, predictors), train)[, -1, drop = FALSE], silent = TRUE)
    x_test <- try(model.matrix(make_formula(outcome_col, predictors), test)[, -1, drop = FALSE], silent = TRUE)
    y_train <- train[[outcome_col]]
    if (inherits(x_train, "try-error") || inherits(x_test, "try-error") || ncol(x_train) == 0) next

    nfolds_use <- min(n_elastic_net_inner_folds, max(3, floor(nrow(train) / 2)))
    fit <- try(glmnet::cv.glmnet(
      x = x_train,
      y = y_train,
      family = "gaussian",
      alpha = alpha,
      nfolds = nfolds_use,
      standardize = FALSE
    ), silent = TRUE)
    if (inherits(fit, "try-error")) next
    preds[i] <- tryCatch(as.numeric(predict(fit, newx = x_test, s = "lambda.min")), error = function(e) NA_real_)

    cf <- try(as.matrix(coef(fit, s = "lambda.min")), silent = TRUE)
    if (!inherits(cf, "try-error")) {
      coef_rows[[i]] <- tibble(
        Model = model_name,
        held_out_animal = mf$AnimalNum[i],
        term = rownames(cf),
        estimate = as.numeric(cf[, 1])
      )
    }
  }

  list(
    predictions = mf %>%
      transmute(
        AnimalNum,
        Group = if ("Group" %in% names(.)) as.character(Group) else NA_character_,
        Sex = if ("Sex" %in% names(.)) as.character(Sex) else NA_character_,
        observed = .data[[outcome_col]],
        predicted = preds,
        residual = observed - predicted,
        abs_residual = abs(residual),
        Model = model_name,
        Method = paste0("LOAO elastic net alpha=", alpha)
      ),
    coefficients = bind_rows(coef_rows)
  )
}

fit_predict_rf_loo <- function(dat, predictors, model_name) {
  if (!has_randomForest || length(predictors) == 0) return(NULL)
  mf <- prepare_model_frame(dat, predictors)
  predictors <- predictors[predictors %in% names(mf)]
  preds <- rep(NA_real_, nrow(mf))

  for (i in seq_len(nrow(mf))) {
    train <- mf[-i, , drop = FALSE]
    test <- mf[i, , drop = FALSE]
    form <- make_formula(outcome_col, predictors)
    fit <- try(randomForest::randomForest(form, data = train, ntree = 500, importance = TRUE), silent = TRUE)
    if (inherits(fit, "try-error")) next
    preds[i] <- tryCatch(as.numeric(predict(fit, newdata = test)), error = function(e) NA_real_)
  }

  list(
    predictions = mf %>%
      transmute(
        AnimalNum,
        Group = if ("Group" %in% names(.)) as.character(Group) else NA_character_,
        Sex = if ("Sex" %in% names(.)) as.character(Sex) else NA_character_,
        observed = .data[[outcome_col]],
        predicted = preds,
        residual = observed - predicted,
        abs_residual = abs(residual),
        Model = paste0(model_name, " nonlinear sensitivity"),
        Method = "LOAO random forest exploratory"
      ),
    coefficients = tibble()
  )
}

main_method <- if (use_elastic_net_if_available && has_glmnet) "elastic_net" else "linear_model"

main_results <- imap(model_specs, function(preds, model_name) {
  if (main_method == "elastic_net" && length(preds) > 0) {
    fit_predict_glmnet_loo(model_dat_raw, preds, model_name, alpha = elastic_net_alpha)
  } else {
    fit_predict_lm_loo(model_dat_raw, preds, model_name)
  }
})

main_predictions <- map_dfr(main_results, "predictions")
main_coefficients <- map_dfr(main_results, "coefficients")

main_performance <- main_predictions %>%
  group_by(Model, Method) %>%
  group_modify(~prediction_metrics(.x$observed, .x$predicted)) %>%
  ungroup() %>%
  arrange(desc(cv_r2_vs_mean), rmse) %>%
  mutate(
    Outcome = primary_outcome_label,
    BinLevel = bin_level,
    AnalysisUse = "primary_conservative_or_regularized"
  )

write_tbl(main_predictions, file.path(output_dir, "tables/systems_ladder_loo_predictions.csv"))
write_tbl(main_coefficients, file.path(output_dir, "tables/systems_ladder_coefficients.csv"))
write_tbl(main_performance, file.path(output_dir, "tables/systems_ladder_performance.csv"))

# Optional nonlinear sensitivity.
if (isTRUE(run_nonlinear_sensitivity) && has_randomForest) {
  rf_specs <- model_specs[c("08b compact behavior", "Full systems compact")]
  rf_results <- imap(rf_specs, ~fit_predict_rf_loo(model_dat_raw, .x, .y))
  rf_results <- rf_results[!vapply(rf_results, is.null, logical(1))]
  rf_predictions <- map_dfr(rf_results, "predictions")
  rf_performance <- rf_predictions %>%
    group_by(Model, Method) %>%
    group_modify(~prediction_metrics(.x$observed, .x$predicted)) %>%
    ungroup() %>%
    arrange(desc(cv_r2_vs_mean), rmse) %>%
    mutate(
      Outcome = primary_outcome_label,
      BinLevel = bin_level,
      AnalysisUse = "exploratory_nonlinear_sensitivity"
    )
  write_tbl(rf_predictions, file.path(output_dir, "tables/nonlinear_sensitivity_loo_predictions.csv"))
  write_tbl(rf_performance, file.path(output_dir, "tables/nonlinear_sensitivity_performance.csv"))
}

# ------------------------------------------------
# INCREMENTAL SUMMARY AGAINST RAW MOVEMENT
# ------------------------------------------------

raw_row <- main_performance %>% filter(Model == "Raw movement only") %>% slice(1)
mean_row <- main_performance %>% filter(Model == "Mean only") %>% slice(1)

incremental_summary <- main_performance %>%
  mutate(
    delta_cv_r2_vs_mean_only = cv_r2_vs_mean - mean_row$cv_r2_vs_mean[1],
    delta_rmse_vs_mean_only = rmse - mean_row$rmse[1],
    delta_cv_r2_vs_raw_movement = cv_r2_vs_mean - raw_row$cv_r2_vs_mean[1],
    delta_rmse_vs_raw_movement = rmse - raw_row$rmse[1],
    Interpretation = case_when(
      Model == "Raw movement only" ~ "Baseline biological signal from early raw movement",
      delta_rmse_vs_raw_movement < 0 & delta_cv_r2_vs_raw_movement > 0 ~ "Improves prediction beyond raw movement",
      delta_rmse_vs_raw_movement >= 0 ~ "Does not improve beyond raw movement",
      TRUE ~ "Uncertain"
    )
  )

write_tbl(incremental_summary, file.path(output_dir, "tables/systems_ladder_incremental_summary.csv"))

# ------------------------------------------------
# PLOTS
